#msgEl { position: fixed; top: 42%; left: 50%; transform: translate(-50%,-50%); color: #ffff00; font-size: 52px; font-weight: bold; text-shadow: 0 0 25px #ff6600, 2px 2px 5px #000; z-index: 25; pointer-events: none; opacity: 0; transition: opacity 0.3s; text-align: center; white-space: nowrap; }
#controls { position: fixed; bottom: 0; left: 0; width: 100%; z-index: 15; pointer-events: none; }
